#!/usr/bin/env python3
"""Temporary bootstrap for the finite-parameter-spectrum manuscript revision.

The compressed payload expands to the reviewed, idempotent revision script.
This bootstrap is removed after the generated manuscript changes are committed.
"""
from __future__ import annotations

import base64
import gzip

PAYLOAD = """"""

source = gzip.decompress(base64.b64decode(PAYLOAD)).decode("utf-8")
exec(compile(source, "<finite-parameter-spectrum-revision>", "exec"))
